{"code": "from hermes_tools import terminal
import os

path = '/tmp/logros'

r = terminal("cd /tmp/logros && python3 -c \"from PIL import Image; import os;\nd=os.listdir('.');\n[print(f'{f}:{Image.open(f).size[0]}x{Image.open(f).size[1]}') for f in sorted(d) if f.endswith('.jpg') or f.endswith('.png')]\"", timeout=30)
dim_lines = [l for l in r['output'].split('\n') if ':' in l and 'x' in l]
dims = {}
for l in dim_lines:
    parts = l.split(':')
    if len(parts) == 2:
        dims[parts[0].strip()] = parts[1].strip()

files = sorted([f for f in os.listdir(path) if f.endswith('.jpg') or f.endswith('.png')])

print("COMPLETE FILE INVENTORY - Logros (Achievements)")
print(f"{'Filename':<55} {'Dim':<15} {'Size':<8} {'Category'}")
print("-"*95)

for f in files:
    size_kb = os.path.getsize(f'{path}/{f}') // 1024
    dim = dims.get(f, '?')

    if f.startswith('Screenshot'):
        cat = 'PHONE SCREENSHOT'
    elif '_n.jpg' in f:
        cat = 'INSTAGRAM POST'
    elif '-' in f:
        w_str, h_str = dim.split('x') if 'x' in dim else ('0','0')
        w, h = int(w_str), int(h_str)
        ratio = w/h if h else 1
        if ratio > 1.4:
            cat = 'ACHIEVEMENT-BADGE (wide)'
        elif ratio > 1.0:
            cat = 'ACHIEVEMENT-BADGE (landscape)'
        elif ratio > 0.85:
            cat = 'ACHIEVEMENT-BADGE (sq)'
        elif ratio > 0.7:
            cat = 'ACHIEVEMENT-BADGE (portrait)'
        else:
            cat = 'ACHIEVEMENT-BADGE (tall)'
    else:
        cat = 'OTHER'

    print(f"{f:<55} {dim:<15} {size_kb:<8} {cat}")
"}

